1	<!DOCTYPE html>
2	<html lang="ko">
3	<head>
4	  <meta charset="UTF-8">
5	  <meta name="viewport" content="width=device-width, initial-scale=1.0">
6	  <title>AI 통합 모니터링 — 전체 아키텍처</title>
7	  <style>
8	    * { box-sizing: border-box; margin: 0; padding: 0; }
9	
10	    body {
11	      font-family: 'Segoe UI', 'Apple SD Gothic Neo', sans-serif;
12	      background: #0d1117;
13	      color: #e6edf3;
14	      padding: 28px 32px;
15	      min-width: 1440px;
16	      zoom: 1.1;
17	    }
18	
19	    /* ── 헤더 ── */
20	    .page-header { text-align: center; margin-bottom: 20px; }
21	    .page-header h1 { font-size: 22px; font-weight: 700; color: #f0f6fc; margin-bottom: 5px; }
22	
23	    /* ── 범례 ── */
24	    .legend { display: flex; gap: 18px; justify-content: center; margin-bottom: 22px; flex-wrap: wrap; }
25	    .legend-item { display: flex; align-items: center; gap: 6px; font-size: 12px; color: #8b949e; }
26	    .legend-dot  { width: 12px; height: 12px; border-radius: 3px; flex-shrink: 0; }
27	    .dot-existing { background: #b45309; border: 1px solid #f97316; }
28	    .dot-new      { background: #1a3424; border: 1px solid #3fb950; }
29	    .dot-internet { background: #0c1929; border: 2px solid #3b82f6; }
30	    .dot-intranet { background: #1a1200; border: 2px solid #d29922; }
31	    .dot-rpm      { background: #374151; border: 1px dashed #9ca3af; }
32	    .dot-docker   { background: #2496ed; border: 1px solid #ffffff; }
33	    .dot-plugin   { background: #1a0a2e; border: 1.5px solid #a855f7; }
34	    .dot-llm      { background: #150f2a; border: 1.5px dashed #7c3aed; }
35	
36	    /* ── 최상위 ── */
37	    .main-wrap { display: flex; flex-direction: column; align-items: center; gap: 0; }
38	
39	    /* ── 공용 섹션 ── */
40	    .section { width: 100%; max-width: 1380px; border-radius: 12px; padding: 16px 18px; }
41	    .sec-label {
42	      font-size: 10px; font-weight: 700; letter-spacing: 1.1px;
43	      text-transform: uppercase; margin-bottom: 12px; opacity: 0.8;
44	    }
45	
46	    /* ── 배포/설정 관리 ── */
47	    .sec-deploy { background: #161b22; border: 1.5px solid #1f4068; }
48	    .sec-deploy .sec-label { color: #58a6ff; }
49	    .deploy-inner { display: flex; gap: 12px; }
50	    .deploy-card {
51	      flex: 1; background: #0d1117; border: 1px solid #1f4068;
52	      border-radius: 8px; padding: 12px 14px;
53	    }
54	    .deploy-card h3 { font-size: 12px; font-weight: 600; color: #58a6ff; margin-bottom: 8px; }
55	    .mono { font-size: 11px; font-family: monospace; color: #8b949e; line-height: 2; }
56	    .mono .hl  { color: #e3b341; }
57	    .mono .ok  { color: #3fb950; }
58	    .mono .bad { color: #f87171; }
59	    .mono .pl  { color: #c084fc; }
60	
61	    /* ── 연결선 ── */
62	    .vconn { display: flex; flex-direction: column; align-items: center; padding: 15px 0; }
63	    .vline { width: 2px; height: 14px; background: #444c56; }
64	    .vtag  {
65	      font-size: 13px; font-weight: 700; color: #f0f6fc; background: #1f2937;
66	      padding: 6px 24px; border-radius: 20px; border: 2px solid #3b82f6;
67	      white-space: nowrap; margin: 4px 0;
68	      box-shadow: 0 0 15px rgba(59,130,246,0.3);
69	    }
70	
71	    /* ── 현장 섹션 ── */
72	    .sec-site { background: #161b22; border: 1.5px solid #238636; }
73	    .sec-site > .sec-label { color: #3fb950; }
74	
75	    /* ── 그리드 (3열 × 2행) ── */
76	    .site-grid {
77	      display: grid;
78	      grid-template-columns: 1fr 1fr 1.2fr;
79	      grid-template-rows: auto auto;
80	      gap: 12px;
81	    }
82	    .cell-internet { grid-column: 1; grid-row: 1; }
83	    .cell-intranet { grid-column: 2; grid-row: 1; }
84	    .cell-infra    { grid-column: 3; grid-row: 1; }
85	    .cell-mon      { grid-column: 1 / 3; grid-row: 2; }
86	    .cell-llm      { grid-column: 3;     grid-row: 2; }
87	
88	    /* ── 망 박스 ── */
89	    .net-box {
90	      border-radius: 10px; padding: 12px 14px; height: 100%;
91	      display: flex; flex-direction: column;
92	    }
93	    .net-internet { background: #0c1929; border: 1.5px solid #3b82f6; }
94	    .net-intranet { background: #1a1200; border: 1.5px solid #d29922; }
95	    .net-label {
96	      font-size: 10px; font-weight: 700; letter-spacing: 0.8px;
97	      text-transform: uppercase; margin-bottom: 10px;
98	    }
99	    .net-internet .net-label { color: #3b82f6; }
100	    .net-intranet .net-label { color: #d29922; }
101	
102	    /* ── 엣지 서버 카드 ── */
103	    .edge-card {
104	      background: #091826; border: 1.5px solid #60a5fa;
105	      border-radius: 8px; padding: 9px 10px;
106	    }
107	    .net-intranet .edge-card { background: #1a1000; border-color: #f59e0b; }
108	    .edge-header { display: flex; align-items: center; gap: 6px; margin-bottom: 7px; flex-wrap: wrap; }
109	    .edge-badge {
110	      font-size: 8px; font-weight: 700; letter-spacing: 0.5px;
111	      background: #1d4ed8; color: #bfdbfe;
112	      padding: 2px 6px; border-radius: 3px;
113	    }
114	    .net-intranet .edge-badge { background: #92400e; color: #fde68a; }
115	    .edge-name { font-size: 12px; font-weight: 700; color: #e6edf3; }
116	    .edge-ip   { font-size: 10px; font-family: monospace; color: #7d8590; margin-left: auto; }
117	    .otlp-out {
118	      margin-top: 7px; font-size: 10px; font-family: monospace;
119	      color: #22d3ee; text-align: right;
120	      padding: 3px 7px; background: #081e22;
121	      border-radius: 4px; border: 1px solid #06b6d4;
122	    }
123	    .zone-arrow {
124	      text-align: center; font-size: 11px; color: #444c56;
125	      padding: 5px 0; font-family: monospace; letter-spacing: 1px;
126	    }
127	
128	    /* ── 서버 풀 카드 ── */
129	    .pool-card {
130	      background: #0d1117; border: 1px dashed #30363d;
131	      border-radius: 8px; padding: 9px 10px;
132	    }
133	    .net-intranet .pool-card { border-color: #3a2800; }
134	    .pool-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 8px; }
135	    .pool-label { font-size: 11px; color: #8b949e; font-weight: 600; }
136	    .pool-count {
137	      font-size: 11px; font-weight: 700; color: #60a5fa;
138	      background: #0c1929; padding: 1px 8px;
139	      border-radius: 10px; border: 1px solid #1d4ed8;
140	    }
141	    .net-intranet .pool-count { color: #fbbf24; background: #1a1000; border-color: #92400e; }
142	
143	    /* ── 컴포넌트 ── */
144	    .comp {
145	      border-radius: 5px; padding: 5px 8px;
146	      display: flex; align-items: center; gap: 5px; flex-wrap: wrap;
147	      margin-bottom: 4px;
148	    }
149	    .comp:last-child { margin-bottom: 0; }
150	    .comp-e { background: #2d1810; border: 1px solid #92400e; }
151	    .comp-role { width: 100%; font-size: 9px; color: #6e7681; font-family: monospace; margin-top: 3px; line-height: 1.4; }
152	    .comp-n { background: #0d1f12; border: 1px solid #166534; }
153	    .comp-name { font-size: 11px; font-weight: 600; flex: 1; }
154	    .comp-e .comp-name { color: #f97316; }
155	    .comp-n .comp-name { color: #4ade80; }
156	    .comp-port { font-size: 10px; font-family: monospace; color: #6e7681; }
157	
158	    /* ── 태그 ── */
159	    .tag {
160	      font-size: 9px; padding: 1px 5px; border-radius: 3px;
161	      font-weight: 700; white-space: nowrap; flex-shrink: 0;
162	    }
163	    .tag-new    { background: #166534; color: #4ade80; }
164	    .tag-rpm    { background: #374151; color: #9ca3af; }
165	    .tag-jar    { background: #7c2d12; color: #fb923c; }
166	    .tag-docker { background: #2496ed; color: #ffffff; border: 1px solid rgba(255,255,255,0.3); }
167	    .tag-gw     { background: #1e3a5f; color: #93c5fd; }
168	    .tag-plugin { background: #2d1f5e; color: #c084fc; }
169	
170	    /* ── 인프라 스택 ── */
171	    .infra-stack { display: flex; flex-direction: column; gap: 8px; height: 100%; }
172	    .infra-item { background: #161b22; border: 1px solid #30363d; border-radius: 8px; padding: 10px 12px; flex: 1; }
173	    .infra-item h4 { font-size: 11px; font-weight: 600; color: #8b949e; margin-bottom: 4px; }
174	    .infra-item p  { font-size: 10px; color: #6e7681; line-height: 1.6; font-family: monospace; }
175	
176	    /* ── 모니터링 서버 ── */
177	    .mon-box {
178	      background: #0c1929; border: 2px solid #3b82f6;
179	      border-radius: 10px; padding: 14px 16px; height: 100%;
180	    }
181	    .mon-title { font-size: 13px; font-weight: 700; color: #e6edf3; margin-bottom: 2px; }
182	    .mon-ip    { font-size: 11px; font-family: monospace; color: #7d8590; margin-bottom: 6px; }
183	    .mon-recv  {
184	      display: inline-block; margin-bottom: 10px;
185	      font-size: 10px; font-family: monospace; color: #22d3ee;
186	      background: #081e22; padding: 3px 9px;
187	      border-radius: 4px; border: 1px solid #06b6d4;
188	    }
189	    .mon-inner { display: grid; grid-template-columns: 1fr 1.6fr; gap: 10px; }
190	    .mon-sub { border-radius: 8px; padding: 10px 12px; }
191	    .mon-sub-e { background: #1a0e00; border: 1px solid #92400e; }
192	    .mon-sub-n { background: #0d1f12; border: 1px solid #166534; }
193	    .mon-sub-label {
194	      font-size: 10px; font-weight: 700; letter-spacing: 0.8px;
195	      text-transform: uppercase; margin-bottom: 8px;
196	    }
197	    .mon-sub-e .mon-sub-label { color: #f97316; }
198	    .mon-sub-n .mon-sub-label { color: #4ade80; }
199	    .mon-comps { display: flex; flex-direction: column; gap: 6px; }
200	    .mc {
201	      border-radius: 6px; padding: 7px 10px;
202	      display: flex; align-items: center; gap: 8px;
203	    }
204	    .mc-e { background: #2d1810; border: 1px solid #92400e; }
205	    .mc-n { background: #0d2a18; border: 1px solid #166534; }
206	    .mc-name { font-size: 12px; font-weight: 700; }
207	    .mc-e .mc-name { color: #f97316; }
208	    .mc-n .mc-name { color: #4ade80; }
209	    .mc-port { font-size: 11px; font-family: monospace; color: #7d8590; }
210	    .mc-role { font-size: 9px; color: #6e7681; font-family: monospace; margin-top: 2px; line-height: 1.4; }
211	    .mc-tags { display: flex; gap: 4px; margin-left: auto; align-items: center; }
212	
213	    /* ── Grafana 플러그인 행 ── */
214	    .plugin-row {
215	      border-radius: 5px; padding: 5px 10px 5px 12px;
216	      display: flex; align-items: center; gap: 8px;
217	      background: #1a0a2e; border: 1px solid #5b21b6;
218	      border-left: 3px solid #a855f7;
219	    }
220	    .plugin-name { font-size: 11px; font-weight: 600; color: #c084fc; flex: 1; }
221	    .plugin-desc { font-size: 10px; color: #7c3aed; }
222	
223	    /* ── LLM 전용 서버 ── */
224	    .llm-box {
225	      background: #1a0f3e; border: 2px solid #7c3aed;
226	      border-radius: 12px; padding: 16px 18px; height: 100%;
227	      box-shadow: 0 0 24px rgba(124,58,237,0.2);
228	    }
229	    .llm-box-title { font-size: 14px; color: #c4b5fd; font-weight: 700; margin-bottom: 5px; }
230	    .llm-box-sub   { font-size: 10px; font-family: monospace; color: #7d8590; margin-bottom: 10px; }
231	    .llm-spec {
232	      margin-top: 10px; font-size: 10px; font-family: monospace;
233	      color: #8b949e; line-height: 1.9;
234	      background: #0d0a1e; padding: 7px 10px;
235	      border-radius: 6px; border: 1px solid #3b2f6e;
236	    }
237	    .llm-spec .sp-k { color: #a78bfa; }
238	    .llm-spec .sp-c { color: #6d28d9; font-size: 9px; letter-spacing: 0.5px; }
239	    .llm-conn {
240	      margin-top: 12px; font-size: 11px; font-weight: 700;
241	      color: #c084fc; background: #2d1f5e;
242	      padding: 6px 10px; border-radius: 6px; border: 1px solid #7c3aed;
243	      text-align: center;
244	    }
245	
246	    /* ── 데이터 흐름 ── */
247	    .flow-panel {
248	      width: 100%; max-width: 1380px;
249	      background: #161b22; border: 1px solid #30363d;
250	      border-radius: 12px; padding: 16px 18px; margin-top: 20px;
251	    }
252	    .flow-title { font-size: 10px; font-weight: 700; color: #7d8590; letter-spacing: 1px; text-transform: uppercase; margin-bottom: 12px; }
253	    .flow-grid { display: grid; grid-template-columns: repeat(4,1fr); gap: 10px; margin-bottom: 10px; }
254	    .fi { background: #0d1117; border-radius: 8px; padding: 10px 12px; border-left: 3px solid; }
255	    .fi.fi-e { background: #1a0a04; border-left-color: #f97316; }
256	    .fi.fi-n { background: #0d1f12; border-left-color: #3fb950; }
257	    .fi.fi-p { background: #1a0a2e; border-left-color: #a855f7; }
258	    .fi-t { font-size: 11px; font-weight: 700; margin-bottom: 4px; }
259	    .fi.fi-e .fi-t { color: #f97316; }
260	    .fi.fi-n .fi-t { color: #3fb950; }
261	    .fi.fi-p .fi-t { color: #c084fc; }
262	    .fi-d { font-size: 10px; color: #6e7681; line-height: 1.7; font-family: monospace; }
263	    .flow-group-label {
264	      font-size: 10px; font-weight: 700; letter-spacing: 0.8px;
265	      padding: 3px 10px; border-radius: 4px; display: inline-block; margin-bottom: 8px;
266	    }
267	    .flow-existing-label { color: #f97316; background: #1a0a04; }
268	    .flow-new-label      { color: #3fb950; background: #0d1f12; margin-top: 10px; }
269	    .flow-plugin-label   { color: #c084fc; background: #1a0a2e; margin-top: 10px; }
270	
271	    footer { text-align: center; font-size: 11px; color: #444c56; margin-top: 25px; }
272	  </style>
273	</head>
274	<body>
275	
276	<div class="page-header">
277	  <h1>AI Agent 기반 지능형 통합 모니터링 — 전체 아키텍처</h1>
278	</div>
279	
280	<div class="legend">
281	  <div class="legend-item"><div class="legend-dot dot-existing"></div>기존 컴포넌트 (운영중)</div>
282	  <div class="legend-item"><div class="legend-dot dot-new"></div>신규 추가 (AI 모니터링 고도화)</div>
283	  <div class="legend-item"><div class="legend-dot dot-internet"></div>인터넷망</div>
284	  <div class="legend-item"><div class="legend-dot dot-intranet"></div>업무망</div>
285	  <div class="legend-item"><div class="legend-dot dot-rpm"></div>RPM 직접설치</div>
286	  <div class="legend-item"><div class="legend-dot" style="background:#7c2d12;border:1px solid #fb923c;"></div>JAR 배포</div>
287	  <div class="legend-item"><div class="legend-dot dot-docker"></div>Docker 컨테이너</div>
288	  <div class="legend-item"><div class="legend-dot dot-plugin"></div>Grafana 플러그인 (오프라인)</div>
289	  <div class="legend-item"><div class="legend-dot dot-llm"></div>LLM 전용 서버 (옵션)</div>
290	</div>
291	
292	<div class="main-wrap">
293	
294	  <!-- ══ 배포/설정 관리 ══ -->
295	  <div class="section sec-deploy">
296	    <div class="sec-label">배포 및 설정 관리 — 폐쇄망 제약 반영 (SSH Push 불가 → Pull 방식)</div>
297	    <div class="deploy-inner">
298	      <div class="deploy-card">
299	        <h3>📦 초기 설치 (1회, 수동)</h3>
300	        <div class="mono">
301	          1. NAS에 <span class="hl">alloy.rpm</span> 업로드<br>
302	          2. <span class="hl">rpm2cpio alloy.rpm | cpio -idmv</span><br>
303	          &nbsp;&nbsp;&nbsp;→ 바이너리 추출 (root 불필요)<br>
304	          3. <span class="ok">nohup ./usr/bin/alloy run config.alloy &amp;</span><br>
305	          4. config URL: <span class="hl">http://엣지서버:9090/config/</span>
306	        </div>
307	      </div>
308	      <div class="deploy-card">
309	        <h3>⚙️ Config 변경 (이후 자동)</h3>
310	        <div class="mono">
311	          1. 엣지서버 Config Server 파일 수정<br>
312	          2. 각 서버 Alloy → HTTP pull <span class="ok">(5분 주기)</span><br>
313	          3. 무중단 반영 <span class="hl">/-/reload API</span><br>
314	          <span class="bad">※ SSH 불필요 — Outbound 단방향만 사용</span>
315	        </div>
316	      </div>
317	      <div class="deploy-card">
318	        <h3>🔒 방화벽 신규 요청 (최소 2개)</h3>
319	        <div class="mono">
320	          <span class="ok">신규</span> ewas1 → mon :<span class="hl">4317</span> &nbsp;(OTLP)<br>
321	          <span class="ok">신규</span> anl1  → mon :<span class="hl">4317</span> &nbsp;(OTLP)<br>
322	          <span class="ok">존 내부</span> 각서버 → 엣지 :<span class="hl">4317 :9090</span><br>
323	          <span class="bad">기존 유지</span> :9091 :3000 그대로
324	        </div>
325	      </div>
326	      <div class="deploy-card">
327	        <h3>🔌 Grafana 플러그인 (오프라인 설치)</h3>
328	        <div class="mono">
329	          1. NAS에 <span class="pl">grafana-llm-app.zip</span> 업로드<br>
330	          2. 압축 해제 → <span class="pl">~/grafana/plugins/</span><br>
331	          3. grafana.ini 설정:<br>
332	          &nbsp;&nbsp;<span class="pl">allow_loading_unsigned_plugins</span><br>
333	          4. LLM URL: <span class="hl">http://ollama:11434/v1/</span>
334	        </div>
335	      </div>
336	    </div>
337	  </div>
338	
339	  <div class="vconn">
340	    <div class="vline"></div>
341	    <div class="vtag">초기 설치: NAS → rpm2cpio (1회) · 이후: HTTP Pull 자동 반영 · 엣지 → mon OTLP :4317 단일 포트</div>
342	    <div class="vline"></div>
343	  </div>
344	
345	  <!-- ══ 현장 ══ -->
346	  <div class="section sec-site">
347	    <div class="sec-label">현장 — 폐쇄망 (인터넷 차단 · 엣지 게이트웨이 집약 구조)</div>
348	
349	    <div class="site-grid">
350	
351	      <!-- Col 1: 인터넷망 -->
352	      <div class="cell-internet">
353	        <div class="net-box net-internet">
354	          <div class="net-label">🌐 인터넷망 (외부망) — 총 32대</div>
355	          <div class="edge-card">
356	            <div class="edge-header">
357	              <span class="edge-badge">EDGE · GATEWAY</span>
358	              <span class="edge-name">new-safe-ewas1</span>
359	              <span class="edge-ip">10.176.62.211</span>
360	            </div>
361	            <div class="comp comp-n">
362	              <span class="comp-name">Alloy Gateway</span>
363	              <span class="comp-port">:4317</span>
364	              <span class="tag tag-new">신규</span>
365	              <span class="tag tag-rpm">RPM</span>
366	              <span class="tag tag-gw">GW</span>
